  Widget _buildParagraph(String text) {
    return Padding(
      padding: EdgeInsets.only(bottom: 12.h),
      child: Text(
        text,
        style: TextStyle(
          fontSize: 12.sp,  // 24rpx ÷ 2 = 12.sp
          height: 1.67,  // 40rpx ÷ 24rpx ≈ 1.67
          color: const Color(0xFF333333),
        ),
      ),
    );
  }
